const FALLBACK_BY_FAMILY = {
  citrus: ["цитрус", "цитрусовий", "citrus", "fresh", "свіжий"],
  floral: ["квітковий", "цветочный", "floral", "flowers", "білі квіти"],
  fruity: ["фруктовий", "фруктовый", "fruity", "juicy", "соковитий"],
  woody: ["деревний", "древесный", "woody", "wood"],
  spicy: ["пряний", "пряный", "spicy", "warm spicy"],
  sweet: ["солодкий", "сладкий", "sweet", "gourmand", "гурманський"],
  fresh: ["свіжий", "свежий", "fresh", "clean", "легкий"],
  aquatic: ["водний", "водяний", "морський", "aquatic", "marine", "water"],
};

function norm(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/ё/g, "е")
    .replace(/ґ/g, "г")
    .replace(/[ʼ’‘`´]/g, "'")
    .replace(/[“”"«»]/g, " ")
    .replace(/&/g, " and ")
    .replace(/\s+/g, " ")
    .trim();
}

function unique(arr = []) {
  return [...new Set((arr || []).map((x) => String(x || "").trim()).filter(Boolean))];
}

function addBasicForms(term) {
  const t = norm(term);
  if (!t || t.length < 2) return [];
  const out = new Set([t]);

  if (/^[а-яіїє' ]+$/i.test(t)) {
    const words = t.split(/\s+/);
    const last = words[words.length - 1];
    const prefix = words.slice(0, -1).join(" ");
    const pushLast = (x) => out.add(prefix ? `${prefix} ${x}` : x);

    if (last.endsWith("а")) {
      const stem = last.slice(0, -1);
      ["и", "у", "ою", "ою", "е"].forEach((e) => pushLast(stem + e));
    } else if (last.endsWith("я")) {
      const stem = last.slice(0, -1);
      ["і", "ю", "ею", "е"].forEach((e) => pushLast(stem + e));
    } else if (last.endsWith("ь")) {
      const stem = last.slice(0, -1);
      ["і", "ю", "ем"].forEach((e) => pushLast(stem + e));
    } else if (!/[aeiou]$/i.test(last)) {
      ["а", "у", "ом", "овий", "евий"].forEach((e) => pushLast(last + e));
    }
  }

  return [...out];
}

function slug(value) {
  return norm(value)
    .replace(/[ʼ’‘`´']/g, " ")
    .replace(/[^a-zа-яіїє0-9]+/gi, "_")
    .replace(/^_+|_+$/g, "") || "note";
}

function buildGeneratedDictionary() {
  const dict = {};

  for (const [key, terms] of Object.entries(CURATED_NOTE_GROUPS)) {
    dict[key] = {
      exact: unique((terms || []).flatMap(addBasicForms)),
      fallback: [],
      source: "curated",
    };
  }

  for (const note of BASE_DB_NOTES) {
    const normalized = norm(note);
    if (!normalized) continue;

    let targetKey = null;
    for (const [key, group] of Object.entries(dict)) {
      if ((group.exact || []).some((term) => norm(term) === normalized)) {
        targetKey = key;
        break;
      }
    }

    const key = targetKey || slug(normalized);
    if (!dict[key]) dict[key] = { exact: [], fallback: [], source: "excel" };
    dict[key].exact = unique([...dict[key].exact, ...addBasicForms(normalized)]);
  }

  // Family fallbacks. These are used only when exact note matches are absent.
  const familyRules = [
    { keys: ["lemon", "orange", "mandarin", "grapefruit", "lime", "bergamot"], family: "citrus" },
    { keys: ["jasmine", "rose", "iris", "violet", "peony", "lotus", "freesia", "gardenia", "ylang", "tuberose", "magnolia"], family: "floral" },
    { keys: ["watermelon", "peach", "apple", "pear", "pineapple", "cherry", "blackcurrant", "raspberry", "strawberry", "melon", "kiwi", "plum", "fig"], family: "fruity" },
    { keys: ["cedar", "sandalwood", "vetiver", "patchouli", "oakmoss"], family: "woody" },
    { keys: ["pepper", "cardamom", "cinnamon", "ginger"], family: "spicy" },
    { keys: ["vanilla", "caramel", "cacao", "tonka", "almond", "coffee"], family: "sweet" },
  ];

  for (const rule of familyRules) {
    for (const key of rule.keys) {
      if (dict[key]) dict[key].fallback = unique([...(dict[key].fallback || []), ...FALLBACK_BY_FAMILY[rule.family]]);
    }
  }

  return dict;
}

const NOTE_DICTIONARY = buildGeneratedDictionary();

module.exports = {
  BASE_DB_NOTES,
  CURATED_NOTE_GROUPS,
  NOTE_DICTIONARY,
  norm,
  unique,
  addBasicForms,
};
